import requests
from requests.exceptions import ConnectTimeout, ReadTimeout, Timeout

CONNECT_TIMEOUT = 5    # seconds
READ_TIMEOUT = 15

def get_weather(city: str) -> dict:
    try:
        resp = requests.get(
            "https://api.weather.example.com/current",
            params={"city": city},
            timeout=(CONNECT_TIMEOUT, READ_TIMEOUT),
        )
        resp.raise_for_status()
        data = resp.json()
        return {
            "city": city,
            "temperature_c": data["temp_c"],
            "condition": data["condition"],
        }
    except ConnectTimeout:
        return {
            "error": "TIMEOUT",
            "phase": "connect",
            "message": f"Could not reach weather service within {CONNECT_TIMEOUT} s",
            "retry_after_seconds": 10,
        }
    except ReadTimeout:
        return {
            "error": "TIMEOUT",
            "phase": "read",
            "message": f"Weather service accepted the connection but did not respond within {READ_TIMEOUT} s",
            "retry_after_seconds": 15,
        }
    except requests.HTTPError as exc:
        return {
            "error": "HTTP_ERROR",
            "status": exc.response.status_code,
            "message": exc.response.text,
        }
    except Exception as exc:
        return {"error": "SERVICE_UNAVAILABLE", "message": str(exc)}

from dataclasses import dataclass

@dataclass(frozen=True)
class TimeoutConfig:
    connect: float
    read: float

    @property
    def as_tuple(self) -> tuple[float, float]:
        return (self.connect, self.read)

# One entry per tool — tune based on observed p99 latency
TOOL_TIMEOUTS: dict[str, TimeoutConfig] = {
    "get_weather":          TimeoutConfig(connect=5,  read=10),
    "search_web":           TimeoutConfig(connect=5,  read=20),
    "execute_sql_query":    TimeoutConfig(connect=3,  read=30),
    "send_email":           TimeoutConfig(connect=5,  read=15),
    "generate_pdf_report":  TimeoutConfig(connect=5,  read=60),
    "get_stock_price":      TimeoutConfig(connect=3,  read=5),
}

DEFAULT_TIMEOUT = TimeoutConfig(connect=5, read=15)

def timeout_for(tool_name: str) -> tuple[float, float]:
    return TOOL_TIMEOUTS.get(tool_name, DEFAULT_TIMEOUT).as_tuple

import time

def remaining(deadline: float) -> float:
    return max(0.0, deadline - time.monotonic())

def call_with_deadline(
    fn,
    *args,
    deadline: float,
    max_read: float = 15.0,
    **kwargs,
) -> dict:
    budget = remaining(deadline)
    if budget < 1.0:
        return {
            "error": "TIMEOUT",
            "message": "Deadline exceeded before tool call started",
        }
    # Cap the read timeout at whatever budget remains, but never exceed max_read
    effective_read = min(budget - 0.5, max_read)
    kwargs["timeout"] = (5.0, effective_read)
    return fn(*args, **kwargs)

# Usage in an agent that chains two tools
def run_research_agent(query: str, total_seconds: float = 30.0) -> str:
    deadline = time.monotonic() + total_seconds

    weather = call_with_deadline(get_weather, query, deadline=deadline)
    if "error" in weather:
        return f"Could not fetch weather: {weather['message']}"

    # second call gets whatever time remains
    result = call_with_deadline(search_web, query, deadline=deadline)
    if "error" in result:
        return f"Could not complete search: {result['message']}"

    return f"Weather: {weather}. Search: {result}"

def search_web(query: str, timeout=(5, 15)) -> dict:
    import requests
    r = requests.get("https://search.example.com/", params={"q": query}, timeout=timeout)
    r.raise_for_status()
    return r.json()

import subprocess
import sqlite3
import threading

# --- SQLite statement timeout via a watchdog thread ---
def execute_query_safe(db_path: str, sql: str, params: tuple, timeout: float = 8.0) -> dict:
    conn = sqlite3.connect(db_path, timeout=5)  # 5 s to acquire the db lock
    timer = threading.Timer(timeout, conn.interrupt)
    timer.start()
    try:
        cur = conn.execute(sql, params)
        rows = cur.fetchall()
        columns = [d[0] for d in cur.description]
        return {"rows": [dict(zip(columns, r)) for r in rows]}
    except sqlite3.OperationalError as exc:
        if "interrupted" in str(exc).lower():
            return {
                "error": "TIMEOUT",
                "message": f"Query exceeded {timeout} s statement timeout",
                "retry_after_seconds": 30,
            }
        return {"error": "DB_ERROR", "message": str(exc)}
    finally:
        timer.cancel()
        conn.close()

# --- Subprocess timeout ---
def run_analysis_script(script_path: str, input_data: str, timeout: float = 20.0) -> dict:
    try:
        result = subprocess.run(
            ["python3", script_path],
            input=input_data,
            capture_output=True,
            text=True,
            timeout=timeout,
        )
        if result.returncode != 0:
            return {"error": "SCRIPT_ERROR", "stderr": result.stderr}
        return {"output": result.stdout}
    except subprocess.TimeoutExpired:
        return {
            "error": "TIMEOUT",
            "message": f"Analysis script exceeded {timeout} s",
            "retry_after_seconds": 60,
        }

import asyncio
import httpx

TIMEOUT = httpx.Timeout(connect=5.0, read=15.0, write=5.0, pool=2.0)

async def get_weather_async(city: str) -> dict:
    async with httpx.AsyncClient(timeout=TIMEOUT) as client:
        try:
            resp = await client.get(
                "https://api.weather.example.com/current",
                params={"city": city},
            )
            resp.raise_for_status()
            data = resp.json()
            return {
                "city": city,
                "temperature_c": data["temp_c"],
                "condition": data["condition"],
            }
        except httpx.ConnectTimeout:
            return {"error": "TIMEOUT", "phase": "connect",
                    "message": "Could not reach weather service", "retry_after_seconds": 10}
        except httpx.ReadTimeout:
            return {"error": "TIMEOUT", "phase": "read",
                    "message": "Weather service stalled mid-response", "retry_after_seconds": 15}
        except httpx.HTTPStatusError as exc:
            return {"error": "HTTP_ERROR", "status": exc.response.status_code,
                    "message": exc.response.text}

async def run_agent_with_deadline(query: str, total_seconds: float = 30.0) -> dict:
    """Run two tool calls within a shared asyncio deadline."""
    try:
        async with asyncio.timeout(total_seconds):
            weather = await get_weather_async(query)
            if "error" in weather:
                return weather
            # second async tool call uses remaining budget automatically
            search = await search_web_async(query)
            return {"weather": weather, "search": search}
    except TimeoutError:
        return {
            "error": "TIMEOUT",
            "message": f"Agent exceeded {total_seconds} s overall deadline",
        }

async def search_web_async(query: str) -> dict:
    async with httpx.AsyncClient(timeout=TIMEOUT) as client:
        resp = await client.get("https://search.example.com/", params={"q": query})
        resp.raise_for_status()
        return resp.json()
